/**
 * @param {string[]} chunks
 * @param {string[]} queries
 * @return {number[]}
 */
function solve(chunks, queries) {
    const s = chunks.join('');
    const wordCounts = new Map();
    const L = s.length;

    /**
     * Checks if a maximal segment composed of letters and hyphens qualifies as a word.
     * A word must:
     * 1. Contain at least one letter.
     * 2. Have hyphens only surrounded by letters.
     * @param {string} segment
     * @returns {boolean}
     */
    const isValidWordSegment = (segment) => {
        if (segment.length === 0) return false;

        let containsLetter = false;

        // Check letter presence and hyphen placement simultaneously
        for (let k = 0; k < segment.length; k++) {
            const char = segment[k];

            if (char >= 'a' && char <= 'z') {
                containsLetter = true;
            } else if (char === '-') {
                // Check surrounding characters
                const prevChar = k > 0 ? segment[k - 1] : null;
                const nextChar = k < segment.length - 1 ? segment[k + 1] : null;

                const isPrevLetter = prevChar && (prevChar >= 'a' && prevChar <= 'z');
                const isNextLetter = nextChar && (nextChar >= 'a' && nextChar <= 'z');

                if (!isPrevLetter || !isNextLetter) {
                    return false;
                }
            } else {
                // This should technically not happen if the segment extraction logic is correct, 
                // but as a safeguard.
                return false; 
            }
        }

        return containsLetter;
    };

    // Step 1 & 2: Parse s and count valid words
    let i = 0;
    while (i < L) {
        const char = s[i];

        // Check if current char is a separator
        const isSeparator = !(char >= 'a' && char <= 'z' || char === '-');

        if (isSeparator) {
            i++;
            continue;
        }

        // Start of a potential word segment
        let j = i;
        while (j < L) {
            const nextChar = s[j];
            const isNextCharWordChar = (nextChar >= 'a' && nextChar <= 'z') || (nextChar === '-');

            if (isNextCharWordChar) {
                j++;
            } else {
                break;
            }
        }

        const segment = s.substring(i, j);

        if (isValidWordSegment(segment)) {
            wordCounts.set(segment, (wordCounts.get(segment) || 0) + 1);
        }

        // Move pointer past the processed segment
        i = j;
    }

    // Step 3: Answer queries
    const results = [];
    for (const query of queries) {
        // The problem statement guarantees queries[i] is an effective word, 
        // but we still check the map for robustness.
        results.push(wordCounts.get(query) || 0);
    }

    return results;
}

