fn is_valid_word_segment(segment_chars: &[char]) -> bool {
    if segment_chars.is_empty() {
        return false;
    }

    let mut contains_letter = false;

    for (k, &char) in segment_chars.iter().enumerate() {
        if char.is_ascii_lowercase() {
            contains_letter = true;
        } else if char == '-' {
            // Hyphen must be surrounded by letters
            let is_prev_letter = k > 0 && segment_chars[k - 1].is_ascii_lowercase();
            let is_next_letter = k < segment_chars.len() - 1 && segment_chars[k + 1].is_ascii_lowercase();

            if !is_prev_letter || !is_next_letter {
                return false;
            }
        } else {
            // Should not happen given how segments are extracted
            return false;
        }
    }

    // Must contain at least one letter
    contains_letter
