fn solve(chunks: Vec<String>, queries: Vec<String>) -> Vec<i64> {
    let s = chunks.join("");
    let chars: Vec<char> = s.chars().collect();
    let n = chars.len();

    let mut word_counts: HashMap<String, i64> = HashMap::new();
    let mut i = 0;

    while i < n {
        let c = chars[i];

        // Check if current char is a word character (letter or hyphen)
        if c.is_ascii_lowercase() || c == '-' {
            // Start of a potential segment
            let mut j = i;
            while j < n && (chars[j].is_ascii_lowercase() || chars[j] == '-') {
                j += 1;
            }

            // Segment runs from i to j-1
            let segment_chars = &chars[i..j];

            // Validate the segment
            if is_valid_word_segment(segment_chars) {
                // Convert to String for map key
                let segment_str: String = segment_chars.iter().collect();
                *word_counts.entry(segment_str).or_insert(0) += 1;
            }

            // Move pointer past the processed segment
            i = j;
        } else {
            // Separator character
            i += 1;
        }
    }

    // Answer queries
    let mut results = Vec::with_capacity(queries.len());
    for query in queries {
        // The problem guarantees queries[i] is an effective word, 
        // but we use get() which returns Option, defaulting to 0.
        let count = *word_counts.get(&query).unwrap_or(&0);
        results.push(count);
    }

    results
}

