        // Extend as long as characters are letters
        while j < n && chars[j].is_ascii_lowercase() {
            j += 1;
        }

        // Extract the segment
        let word: String = chars[start..j].iter().collect();

        // Store count
        *word_counts.entry(word).or_insert(0) += 1;

        // Move pointer past the segment
        i = j;
    }

    // Answer queries
    let mut results = Vec::with_capacity(queries.len());
    for query in queries {
        let count = *word_counts.get(&query).unwrap_or(&0);
        results.push(count);
    }

    results
